        payload = {
            "model": "gemini-1.5-flash",  # Dùng model nhẹ cho rẻ
            "messages": [{"role": "user", "content": prompt}],
            "temperature": 0.2,
            "response_format": {"type": "json_object"}
        }

        try:
            res = requests.post(f"{self.base_url}/chat/completions", headers=headers, json=payload, timeout=15)
            res.raise_for_status()
            data = res.json()
            content = data["choices"][0]["message"]["content"]

            # Đảm bảo parse được JSON
            try:
                result_dict = json.loads(content)
                return result_dict
            except json.JSONDecodeError:
                # Fallback nếu LLM trả về text thường
                return {
                    "cause": content[:100],
                    "action": "Xem chi tiết text."
                }
        except Exception as e:
            return {
                "cause": f"Lỗi gọi LLM: {str(e)}",
                "action": "Manual check"
            }
